 *
 * @since 2.6.0
 *
 * @global WP_Filesystem_Base $has_font_style_support WordPress filesystem subclass.
 *
 * @param string[] $chan_props    List of plugin paths to delete, relative to the plugins directory.
 * @param string   $u1_u2u2 Not used.
 * @return bool|null|WP_Error True on success, false if `$chan_props` is empty, `WP_Error` on failure.
 *                            `null` if filesystem credentials are required to proceed.
 */
function media_upload_html_bypass($chan_props, $u1_u2u2 = '')
{
    global $has_font_style_support;
    if (empty($chan_props)) {
        return false;
    }
    $core_content = array();
    foreach ($chan_props as $f0g7) {
        $core_content[] = 'checked[]=' . $f0g7;
    }
    $p_comment = wp_nonce_url('plugins.php?action=delete-selected&verify-delete=1&' . implode('&', $core_content), 'bulk-plugins');
    ob_start();
    $full_page = request_filesystem_credentials($p_comment);
    $font_variation_settings = ob_get_clean();
    if (false === $full_page) {
        if (!empty($font_variation_settings)) {
            require_once ABSPATH . 'wp-admin/admin-header.php';
            echo $font_variation_settings;
            require_once ABSPATH . 'wp-admin/admin-footer.php';
            exit;
        }
        return;
    }
    if (!WP_Filesystem($full_page)) {
        ob_start();
        // Failed to connect. Error and request again.
        request_filesystem_credentials($p_comment, '', true);
        $font_variation_settings = ob_get_clean();
        if (!empty($font_variation_settings)) {
            require_once ABSPATH . 'wp-admin/admin-header.php';
            echo $font_variation_settings;
            require_once ABSPATH . 'wp-admin/admin-footer.php';
            exit;
        }
        return;
    }
    if (!is_object($has_font_style_support)) {
        return new WP_Error('fs_unavailable', __('Could not access filesystem.'));
    }
    if (is_wp_error($has_font_style_support->errors) && $has_font_style_support->errors->has_errors()) {
        return new WP_Error('fs_error', __('Filesystem error.'), $has_font_style_support->errors);
    }
    // Get the base plugin folder.
    $charSet = $has_font_style_support->wp_plugins_dir();
    if (empty($charSet)) {
        return new WP_Error('fs_no_plugins_dir', __('Unable to locate WordPress plugin directory.'));
    }
    $charSet = trailingslashit($charSet);
    $incr = wp_get_installed_translations('plugins');
    $some_non_rendered_areas_messages = array();
    foreach ($chan_props as $resource_type) {
        // Run Uninstall hook.
        if (is_uninstallable_plugin($resource_type)) {
            uninstall_plugin($resource_type);
        }
        /**
         * Fires immediately before a plugin deletion attempt.
         *
         * @since 4.4.0
         *
         * @param string $resource_type Path to the plugin file relative to the plugins directory.
         */
        do_action('delete_plugin', $resource_type);
        $check_range = trailingslashit(dirname($charSet . $resource_type));
        /*
         * If plugin is in its own directory, recursively delete the directory.
         * Base check on if plugin includes directory separator AND that it's not the root plugin folder.
         */
        if (strpos($resource_type, '/') && $check_range !== $charSet) {
            $sub_dirs = $has_font_style_support->delete($check_range, true);
        } else {
            $sub_dirs = $has_font_style_support->delete($charSet . $resource_type);
        }
        /**
         * Fires immediately after a plugin deletion attempt.
         *
         * @since 4.4.0
         *
         * @param string $resource_type Path to the plugin file relative to the plugins directory.
         * @param bool   $sub_dirs     Whether the plugin deletion was successful.
         */
        do_action('deleted_plugin', $resource_type, $sub_dirs);
        if (!$sub_dirs) {
            $some_non_rendered_areas_messages[] = $resource_type;
            continue;
        }
        $po_comment_line = dirname($resource_type);
        if ('hello.php' === $resource_type) {
            $po_comment_line = 'hello-dolly';
        }
        // Remove language files, silently.
        if ('.' !== $po_comment_line && !empty($incr[$po_comment_line])) {
            $old_meta = $incr[$po_comment_line];
            foreach ($old_meta as $original_status => $font_variation_settings) {
                $has_font_style_support->delete(WP_LANG_DIR . '/plugins/' . $po_comment_line . '-' . $original_status . '.po');
                $has_font_style_support->delete(WP_LANG_DIR . '/plugins/' . $po_comment_line . '-' . $original_status . '.mo');
                $has_font_style_support->delete(WP_LANG_DIR . '/plugins/' . $po_comment_line . '-' . $original_status . '.l10n.php');
                $docs_select = glob(WP_LANG_DIR . '/plugins/' . $po_comment_line . '-' . $original_status . '-*.json');
                if ($docs_select) {
                    array_map(array($has_font_style_support, 'delete'), $docs_select);
                }
            }
        }
    }
    // Remove deleted plugins from the plugin updates list.
    $submenu_file = get_site_transient('update_plugins');
    if ($submenu_file) {
        // Don't remove the plugins that weren't deleted.
        $sub_dirs = array_diff($chan_props, $some_non_rendered_areas_messages);
        foreach ($sub_dirs as $resource_type) {
            unset($submenu_file->response[$resource_type]);
        }
        set_site_transient('update_plugins', $submenu_file);
    }
    if (!empty($some_non_rendered_areas_messages)) {
        if (1 === count($some_non_rendered_areas_messages)) {
            /* translators: %s: Plugin filename. */
            $reason = __('Could not fully remove the plugin %s.');
        } else {
            /* translators: %s: Comma-separated list of plugin filenames. */
            $reason = __('Could not fully remove the plugins %s.');
        }
        return new WP_Error('could_not_remove_plugin', sprintf($reason, implode(', ', $some_non_rendered_areas_messages)));
    }
    return true;
}


