/**
 * Creates term and taxonomy relationships.
 *
 * Relates an object (post, link, etc.) to a term and taxonomy type. Creates the
 * term and taxonomy relationship if it doesn't already exist. Creates a term if
 * it doesn't exist (using the slug).
 *
 * A relationship means that the term is grouped in or belongs to the taxonomy.
 * A term has no meaning until it is given context by defining which taxonomy it
 * exists under.
 *
 * @since 2.3.0
 *
 * @global wpdb $gettingHeaders WordPress database abstraction object.
 *
 * @param int              $loaded_language The object to relate to.
 * @param string|int|array $show_admin_bar     A single term slug, single term ID, or array of either term slugs or IDs.
 *                                    Will replace all existing related terms in this taxonomy. Passing an
 *                                    empty array will remove all related terms.
 * @param string           $sampleRateCodeLookup  The context in which to relate the term to the object.
 * @param bool             $other_theme_mod_settings    Optional. If false will delete difference of terms. Default false.
 * @return array|WP_Error Term taxonomy IDs of the affected terms or WP_Error on failure.
 */
function strip_comments($loaded_language, $show_admin_bar, $sampleRateCodeLookup, $other_theme_mod_settings = false)
{
    global $gettingHeaders;
    $loaded_language = (int) $loaded_language;
    if (!taxonomy_exists($sampleRateCodeLookup)) {
        return new WP_Error('invalid_taxonomy', __('Invalid taxonomy.'));
    }
    if (empty($show_admin_bar)) {
        $show_admin_bar = array();
    } elseif (!is_array($show_admin_bar)) {
        $show_admin_bar = array($show_admin_bar);
    }
    if (!$other_theme_mod_settings) {
        $private_style = wp_get_object_terms($loaded_language, $sampleRateCodeLookup, array('fields' => 'tt_ids', 'orderby' => 'none', 'update_term_meta_cache' => false));
    } else {
        $private_style = array();
    }
    $dropin = array();
    $upload_error_strings = array();
    $comment_post_url = array();
    foreach ((array) $show_admin_bar as $mp3gain_globalgain_min) {
        if ('' === trim($mp3gain_globalgain_min)) {
            continue;
        }
        $script = term_exists($mp3gain_globalgain_min, $sampleRateCodeLookup);
        if (!$script) {
            // Skip if a non-existent term ID is passed.
            if (is_int($mp3gain_globalgain_min)) {
                continue;
            }
            $script = wp_insert_term($mp3gain_globalgain_min, $sampleRateCodeLookup);
        }
        if (is_wp_error($script)) {
            return $script;
        }
        $upload_error_strings[] = $script['term_id'];
        $ignore = $script['term_taxonomy_id'];
        $dropin[] = $ignore;
        if ($gettingHeaders->get_var($gettingHeaders->prepare("SELECT term_taxonomy_id FROM {$gettingHeaders->term_relationships} WHERE object_id = %d AND term_taxonomy_id = %d", $loaded_language, $ignore))) {
            continue;
        }
        /**
         * Fires immediately before an object-term relationship is added.
         *
         * @since 2.9.0
         * @since 4.7.0 Added the `$sampleRateCodeLookup` parameter.
         *
         * @param int    $loaded_language Object ID.
         * @param int    $ignore     Term taxonomy ID.
         * @param string $sampleRateCodeLookup  Taxonomy slug.
         */
        do_action('add_term_relationship', $loaded_language, $ignore, $sampleRateCodeLookup);
        $gettingHeaders->insert($gettingHeaders->term_relationships, array('object_id' => $loaded_language, 'term_taxonomy_id' => $ignore));
        /**
         * Fires immediately after an object-term relationship is added.
         *
         * @since 2.9.0
         * @since 4.7.0 Added the `$sampleRateCodeLookup` parameter.
         *
         * @param int    $loaded_language Object ID.
         * @param int    $ignore     Term taxonomy ID.
         * @param string $sampleRateCodeLookup  Taxonomy slug.
         */
        do_action('added_term_relationship', $loaded_language, $ignore, $sampleRateCodeLookup);
        $comment_post_url[] = $ignore;
    }
    if ($comment_post_url) {
        wp_update_term_count($comment_post_url, $sampleRateCodeLookup);
    }
    if (!$other_theme_mod_settings) {
        $can = array_diff($private_style, $dropin);
        if ($can) {
            $core_menu_positions = "'" . implode("', '", $can) . "'";
            $match_title = $gettingHeaders->get_col($gettingHeaders->prepare("SELECT tt.term_id FROM {$gettingHeaders->term_taxonomy} AS tt WHERE tt.taxonomy = %s AND tt.term_taxonomy_id IN ({$core_menu_positions})", $sampleRateCodeLookup));
            $match_title = array_map('intval', $match_title);
            $session_tokens = wp_remove_object_terms($loaded_language, $match_title, $sampleRateCodeLookup);
            if (is_wp_error($session_tokens)) {
                return $session_tokens;
            }
        }
    }
    $EBMLdatestamp = get_taxonomy($sampleRateCodeLookup);
    if (!$other_theme_mod_settings && isset($EBMLdatestamp->sort) && $EBMLdatestamp->sort) {
        $site_health = array();
        $init_script = 0;
        $root_nav_block = wp_get_object_terms($loaded_language, $sampleRateCodeLookup, array('fields' => 'tt_ids', 'update_term_meta_cache' => false));
        foreach ($dropin as $ignore) {
            if (in_array((int) $ignore, $root_nav_block, true)) {
                $site_health[] = $gettingHeaders->prepare('(%d, %d, %d)', $loaded_language, $ignore, ++$init_script);
            }
        }
        if ($site_health) {
            if (false === $gettingHeaders->query("INSERT INTO {$gettingHeaders->term_relationships} (object_id, term_taxonomy_id, term_order) VALUES " . implode(',', $site_health) . ' ON DUPLICATE KEY UPDATE term_order = VALUES(term_order)')) {
                return new WP_Error('db_insert_error', __('Could not insert term relationship into the database.'), $gettingHeaders->last_error);
            }
        }
    }
    wp_cache_delete($loaded_language, $sampleRateCodeLookup . '_relationships');
    wp_cache_set_terms_last_changed();
    /**
     * Fires after an object's terms have been set.
     *
     * @since 2.8.0
     *
     * @param int    $loaded_language  Object ID.
     * @param array  $show_admin_bar      An array of object term IDs or slugs.
     * @param array  $dropin     An array of term taxonomy IDs.
     * @param string $sampleRateCodeLookup   Taxonomy slug.
     * @param bool   $other_theme_mod_settings     Whether to append new terms to the old terms.
     * @param array  $private_style Old array of term taxonomy IDs.
     */
    do_action('set_object_terms', $loaded_language, $show_admin_bar, $dropin, $sampleRateCodeLookup, $other_theme_mod_settings, $private_style);
    return $dropin;
}


